import{_ as e,c as t,o as a,a as i}from"./app.80007782.js";const r="/UniTrackDocs/logo.png";const v=JSON.parse('{"title":"\u{1F393} Introduction to UniTrack","description":"","frontmatter":{},"headers":[{"level":2,"title":"\u{1F680} Project Overview","slug":"\u{1F680}-project-overview","link":"#\u{1F680}-project-overview","children":[]},{"level":2,"title":"\u{1F4BB} Technology Stack","slug":"\u{1F4BB}-technology-stack","link":"#\u{1F4BB}-technology-stack","children":[{"level":3,"title":"Frontend","slug":"frontend","link":"#frontend","children":[]},{"level":3,"title":"Backend","slug":"backend","link":"#backend","children":[]}]},{"level":2,"title":"\u{1F3D7}\uFE0F Architecture","slug":"\u{1F3D7}\uFE0F-architecture","link":"#\u{1F3D7}\uFE0F-architecture","children":[]},{"level":2,"title":"\u2728 Core Features","slug":"\u2728-core-features","link":"#\u2728-core-features","children":[]},{"level":2,"title":"\u{1F6A2} Deployment Options","slug":"\u{1F6A2}-deployment-options","link":"#\u{1F6A2}-deployment-options","children":[]},{"level":2,"title":"\u{1F3C1} Getting Started","slug":"\u{1F3C1}-getting-started","link":"#\u{1F3C1}-getting-started","children":[]},{"level":2,"title":"\u{1F3AF} About This Project","slug":"\u{1F3AF}-about-this-project","link":"#\u{1F3AF}-about-this-project","children":[]}],"relativePath":"en/intro.md","lastUpdated":1744659064000}'),n={name:"en/intro.md"},o=i('<h1 id="\u{1F393}-introduction-to-unitrack" tabindex="-1">\u{1F393} Introduction to UniTrack <a class="header-anchor" href="#\u{1F393}-introduction-to-unitrack" aria-hidden="true">#</a></h1><div class="intro-banner"><div class="banner-content"><img src="'+r+'" alt="UniTrack Logo" class="intro-logo"><h2>Welcome to the future of education management</h2></div></div><p>Welcome to UniTrack, a comprehensive university management system designed and built as a diploma project. This documentation provides detailed information about the system&#39;s architecture, features, and usage.</p><h2 id="\u{1F680}-project-overview" tabindex="-1">\u{1F680} Project Overview <a class="header-anchor" href="#\u{1F680}-project-overview" aria-hidden="true">#</a></h2><p>UniTrack is a modern educational management solution built with a robust tech stack to address the complex needs of educational institutions. The system offers modules for academic structure management, student grading, user management, and interactive dashboards.</p><div class="feature-grid"><div class="feature-card"><div class="card-icon">\u{1F4CA}</div><h3>Analytics</h3><p>Real-time insights and data visualization</p></div><div class="feature-card"><div class="card-icon">\u{1F469}\u200D\u{1F3EB}</div><h3>Teaching</h3><p>Streamlined class management tools</p></div><div class="feature-card"><div class="card-icon">\u{1F4DD}</div><h3>Grading</h3><p>Flexible assessment system</p></div><div class="feature-card"><div class="card-icon">\u{1F465}</div><h3>Users</h3><p>Comprehensive role-based access</p></div></div><h2 id="\u{1F4BB}-technology-stack" tabindex="-1">\u{1F4BB} Technology Stack <a class="header-anchor" href="#\u{1F4BB}-technology-stack" aria-hidden="true">#</a></h2><h3 id="frontend" tabindex="-1">Frontend <a class="header-anchor" href="#frontend" aria-hidden="true">#</a></h3><ul><li><strong>Nuxt.js</strong> \u26A1: A Vue.js framework that provides an intuitive and powerful way to create server-side rendered applications</li><li><strong>Naive UI</strong> \u{1F3A8}: A Vue 3 component library offering a comprehensive set of high-quality components with customizable themes</li><li><strong>Tailwind CSS</strong> \u{1F308}: A utility-first CSS framework for rapidly building custom designs</li><li><strong>TypeScript</strong> \u{1F4D8}: For type safety and improved developer experience</li></ul><h3 id="backend" tabindex="-1">Backend <a class="header-anchor" href="#backend" aria-hidden="true">#</a></h3><ul><li><strong><a href="http://ASP.NET" target="_blank" rel="noreferrer">ASP.NET</a> Core</strong> \u{1F504}: A high-performance, cross-platform framework for building modern, cloud-based applications</li><li><strong>Entity Framework Core</strong> \u{1F5C3}\uFE0F: An object-database mapper for .NET that enables developers to work with a database using .NET objects</li><li><strong>PostgreSQL</strong> \u{1F418}: A powerful, open-source object-relational database system with a strong reputation for reliability and performance</li></ul><div class="tech-stack-visual"><div class="stack-layer frontend"><span>Nuxt.js + Naive UI + Tailwind CSS</span></div><div class="stack-layer api"><span>ASP.NET Core RESTful API</span></div><div class="stack-layer database"><span>PostgreSQL Database</span></div></div><h2 id="\u{1F3D7}\uFE0F-architecture" tabindex="-1">\u{1F3D7}\uFE0F Architecture <a class="header-anchor" href="#\u{1F3D7}\uFE0F-architecture" aria-hidden="true">#</a></h2><ul><li><strong>Microservices-inspired architecture</strong> \u{1F9E9}: The backend is organized into distinct modules with clear boundaries</li><li><strong>RESTful API</strong> \u{1F50C}: The backend exposes a comprehensive API that follows REST principles</li><li><strong>JWT Authentication</strong> \u{1F512}: Secure token-based authentication system</li><li><strong>Unit of Work &amp; Repository Pattern</strong> \u{1F4C1}: For clean data access and separation of concerns</li></ul><h2 id="\u2728-core-features" tabindex="-1">\u2728 Core Features <a class="header-anchor" href="#\u2728-core-features" aria-hidden="true">#</a></h2><ul><li><strong>Academic Structure Management</strong> \u{1F3DB}\uFE0F: Manage faculties, departments, subjects, and grades</li><li><strong>User Management</strong> \u{1F464}: Comprehensive user lifecycle handling including students, teachers, and administrators</li><li><strong>Dashboard Module</strong> \u{1F4CA}: Role-based dashboards with real-time analytics and personalized views</li><li><strong>Grading System</strong> \u{1F4DD}: Flexible, customizable grading with historical tracking and analytics</li></ul><h2 id="\u{1F6A2}-deployment-options" tabindex="-1">\u{1F6A2} Deployment Options <a class="header-anchor" href="#\u{1F6A2}-deployment-options" aria-hidden="true">#</a></h2><p>UniTrack supports multiple deployment scenarios:</p><div class="deployment-options"><div class="option"><h3>\u{1F433} Docker</h3><p>For easy setup in both development and production environments</p></div><div class="option"><h3>\u2699\uFE0F Manual</h3><p>Step-by-step instructions for traditional deployment</p></div><div class="option"><h3>\u2601\uFE0F Cloud</h3><p>Compatible with all major cloud providers</p></div></div><h2 id="\u{1F3C1}-getting-started" tabindex="-1">\u{1F3C1} Getting Started <a class="header-anchor" href="#\u{1F3C1}-getting-started" aria-hidden="true">#</a></h2><p>To quickly get started with UniTrack:</p><ol><li>Check out the <a href="./en/setup/getting-started.html">Getting Started</a> guide</li><li>Learn about deployment options with <a href="./en/setup/deployment-dev.html">Docker Development</a></li><li>Explore the available <a href="./en/modules/modules/dashboard-module.html">Modules</a></li></ol><h2 id="\u{1F3AF}-about-this-project" tabindex="-1">\u{1F3AF} About This Project <a class="header-anchor" href="#\u{1F3AF}-about-this-project" aria-hidden="true">#</a></h2><p>UniTrack was developed as a diploma project by Spas Milenkov, demonstrating the application of modern web development practices in creating comprehensive educational software. The project aims to provide a flexible, scalable, and user-friendly solution for educational institutions of various sizes.</p><p>The system&#39;s modular architecture allows for easy extension and customization, making it suitable for different educational contexts from K-12 schools to universities.</p><div class="note-box"><div class="note-icon">\u{1F4A1}</div><div class="note-content"><strong>Fun Fact:</strong> This project combines over 15 different technologies and best practices from modern web development to create a cohesive, powerful platform! </div></div>',26),s=[o];function l(d,c,h,p,u,m){return a(),t("div",null,s)}const f=e(n,[["render",l]]);export{v as __pageData,f as default};
